const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=parseInt(input[idx++],10);
let results=[];
for(let t=0;t<T;t++){
  let n=BigInt(input[idx++]);
  let sum=0n;
  let prod=1n;
  if(n===0n){ sum=0n; prod=0n; } else {
    while(n!==0n){
      const d=n%10n;
      sum+=d;
      prod*=d;
      n=n/10n;
    }
  }
  results.push(`${sum.toString()} ${prod.toString()}`);
}
console.log(results.join('\n'));
